const http = require('http');
const fs = require('fs');

const options = {
  hostname: 'the-agent-company.com',
  port: 8092,
  path: '/remote.php/dav/files/theagentcompany/Documents/command.txt',
  method: 'GET',
  auth: 'theagentcompany:theagentcompany'
};

let data = '';
const req = http.request(options, (res) => {
  res.on('data', chunk => data += chunk);
  res.on('end', () => {
    fs.writeFileSync('/tmp/mcp-workspace/command.txt', data);
    console.log('CONTENT:', data);
  });
});
req.on('error', err => console.error('ERROR:', err.message));
req.end();


